create table dirkspzm32.lvs_prod_linie (
    sid                     varchar2(2 char) not null enable,
    firma_nr                number(2, 0) not null enable,
    linie_nr                number(*, 5) not null enable,
    linie_name              varchar2(30 char) not null enable,
    linie_aktiv             number(*, 0) not null enable,
    linie_produktionsdatum  date,
    linie_lagerort          number(*, 5),
    lte_name                varchar2(22 char) not null enable,
    lte_vol_hoehe           number(*, 3),
    lte_vol_breite          number(*, 3),
    lte_vol_tiefe           number(*, 3),
    res_id                  number(*, 0),
    res_string              varchar2(80 char),
    adress_id               number(*, 0),
    lte_eti_druck_status    varchar2(10 char) default 'SD',
    packschema_kopf_id      varchar2(20 char),
    auto_depal              varchar2(10 char),
    wickelprogramm          varchar2(4 char),
    wickelprogramm_einl     varchar2(4 char),
    erstellen_mit_transport varchar2(1 char) default 'F'
);

alter table dirkspzm32.lvs_prod_linie
    add constraint check_creation_with_transport
        check ( erstellen_mit_transport in ( 'F', 'T' ) ) enable;

alter table dirkspzm32.lvs_prod_linie
    add constraint check_prod_linie_auto_depal
        check ( auto_depal in ( null, 'FALSE', 'LAGE', 'LHM' ) ) enable;

alter table dirkspzm32.lvs_prod_linie
    add constraint pk_lvs_prod_linie
        primary key ( linie_nr,
                      firma_nr,
                      sid )
            using index enable;


